import React, { useState } from 'react'; 
import axios from 'axios'; 
 
const Search = () => { 
    const [keyword, setKeyword] = useState(''); 
    const [results, setResults] = useState([]); 
 
    const handleSearch = async () => { 
        if (!keyword) return; 
        try { 
            const res = await axios.get(`http://localhost:5000/api/songs/search?q=${keyword}`); 
            setResults(res.data); 
        } catch (err) { console.error("Loi tim kiem:", err); } 
    }; 
 
    return ( 
        <div style={{ padding: '20px', maxWidth: '1000px', margin: '0 auto', fontFamily: 'Arial' }}> 
            <h2 style={{ textAlign: 'center', marginBottom: '30px' }}>TÌM KIẾM BÀI HÁT</h2> 
            <div style={{ display: 'flex', gap: '10px', marginBottom: '40px' }}> 
                <input 
                    type="text" 
                    placeholder="Nhập tên bài hát hoặc ca sĩ..." 
                    value={keyword} 
                    onChange={(e) => setKeyword(e.target.value)} 
                    style={{ flex: 1, padding: '12px 20px', borderRadius: '30px', border: '1px solid #ccc', outline: 'none', fontSize: '16px' }} 
                /> 
                <button onClick={handleSearch} style={{ padding: '10px 30px', background: '#28a745', color: '#fff', border: 'none', borderRadius: '30px', cursor: 'pointer', fontWeight: 'bold' }}>TÌM KIẾM</button> 
            </div> 
 
            <div style={{ display: 'flex', flexDirection: 'column', gap: '20px' }}> 
                {results.length > 0 ? results.map((song) => ( 
                    <div key={song._id} style={{ display: 'flex', alignItems: 'center', padding: '15px 30px', border: '1px solid #eee', borderRadius: '15px', background: '#fff', boxShadow: '0 4px 12px rgba(0,0,0,0.05)', justifyContent: 'space-between' }}> 
                        <div style={{ display: 'flex', alignItems: 'center' }}> 
                            <img src={song.imageUrl ? `http://localhost:5000${song.imageUrl}` : 'https://via.placeholder.com/80'} style={{ width: '80px', height: '80px', marginRight: '25px', borderRadius: '10px', objectFit: 'cover' }} /> 
                            <div style={{ textAlign: 'left' }}> 
                                <div style={{ fontWeight: 'bold', fontSize: '20px' }}>{song.title}</div> 
                                <div style={{ fontSize: '16px', color: '#888' }}>{song.artist}</div> 
                            </div> 
                        </div> 
                        <div style={{color: '#28a745', fontWeight: 'bold'}}>Sẵn sàng phát</div> 
                    </div> 
                )) : <p style={{textAlign:'center', color:'#999'}}>Chưa có kết quả nào. Hãy thử tìm từ khóa khác!</p>} 
            </div> 
        </div> 
    ); 
}; 
export default Search;
